function InputFormForList({TextPlaceholder, type = "text",accept, Id, funct,index, item}) {
  return (
    <input
    type={type}
    className={"input mini-input"}
    placeholder={TextPlaceholder}
    accept={accept}
    id={Id}
    onChange={(e) => funct(index, e.target.value)}
    />
  );
}

export default InputFormForList;
